css:
/* ALL CAPS OVERRIDE FOR TRUE 70s FEEL */
* { font-family: 'VT323', ui-monospace, monospace !important; text-transform: uppercase !important; letter-spacing: 0.15em !important; }

/* Phosphor Glow & Selection */
::selection { background: #33ff33 !important; color: #000 !important; }
::-moz-selection { background: #33ff33 !important; color: #000 !important; }
h1, h2, h3, h4, span, p, a, button, input, textarea, td, th { text-shadow: 0 0 4px rgba(51, 255, 51, 0.7) !important; }
svg { filter: drop-shadow(0 0 3px rgba(51, 255, 51, 0.8)); }

/* Force Mono Color Palette (Kill all default Tailwind colors) */
.text-theme-danger, .text-theme-warning, .text-theme-info, .text-theme-success { color: #33ff33 !important; }
.bg-theme-danger, .bg-theme-warning, .bg-theme-info, .bg-theme-success { background-color: #33ff33 !important; color: #000 !important; }
.border-theme-danger, .border-theme-warning, .border-theme-info, .border-theme-success { border-color: #33ff33 !important; }

/* Retro Input & Buttons */
input, textarea, select { caret-color: #33ff33; border: 1px solid #33ff33 !important; background: #000 !important; color: #33ff33 !important; }
.bg-theme-surface, .card { border: 1px solid #33ff33 !important; background: #000 !important; box-shadow: none !important; }
.btn-primary, .btn-secondary { border: 1px solid #33ff33 !important; box-shadow: none !important; background: #000 !important; color: #33ff33 !important; }
.btn-primary:hover, .btn-secondary:hover { background: #33ff33 !important; color: #000 !important; }

/* Blinking Prompt for Active Nav */
@keyframes blinkCaret { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
.skin-sidebar-item.active::before { content: '>'; position: absolute; left: 8px; animation: blinkCaret 1s step-end infinite; }
